def merge_cells(data):
    if not data or not isinstance(data, list):
        return []

    merged_data = []
    previous_value = None
    merged_row = []

    for row in data:
        if not isinstance(row, list):
            continue

        new_row = []
        for value in row:
            if value == previous_value:
                new_row.append("")  # Merge cell by adding an empty string
            else:
                new_row.append(value)
                previous_value = value

        merged_data.append(new_row)
        previous_value = None  # Reset for the next row

    return merged_data

def solve(*args):
    if len(args) != 1:
        return None
    return merge_cells(args[0])
